{"command": "python3 -c "
import fitz

# Check all PDFs more carefully - get text with font sizes to find real titles
pdfs_to_check = ['1a43020f6c08.pdf', 'd0a480b001f5.pdf', 'adee683ca18e.pdf', 'c1b9051daa2e.pdf']

for pdf in pdfs_to_check:
    doc = fitz.open(f'/tmp_workspace/{pdf}')
    page = doc[0]
    blocks = page.get_text('dict')['blocks']

    print(f'=== {pdf} ===')
    items = []
    for block in blocks:
        if 'lines' in block:
            for line in block['lines']:
                for span in line['spans']:
                    t = span['text'].strip()
                    if t:
                        items.append((span['size'], span['origin'][1], t))

    # Sort by size desc to see largest
    items.sort(key=lambda x: -x[0])
    for size, y, t in items[:10]:
        print(f'  size={size:.1f} y={y:.0f}: {t[:80]}')
    doc.close()
    print()
