import fitz

doc = fitz.open('/tmp_workspace/9eac27775c25.pdf')
print(f'Pages: {len(doc)}')
# Search for tables across pages
for i in range(min(15, len(doc))):
    text = doc[i].get_text('text')
    if 'table' in text.lower() or 'Table' in text:
        lines = [l.strip() for l in text.split('\n') if l.strip()]
        for j, line in enumerate(lines):
            if 'table' in line.lower() and len(line) < 200:
                print(f'Page {i}: {line}')
doc.close()
